# # Generated by create-crm-factory.ps1
Set-StrictMode -Version Latest

function New-TypeArtifact {

    param(
        [string]$Module
    )

    Write-TextFile `
        -Path (Get-ModuleFile $Module "Type") `
        -Content @(
"export interface $Module {",
"    id: string;",
"    createdAt?: string;",
"    updatedAt?: string;",
"}"
)

    Write-Success "Type Generated"

}

