function New-ValidationArtifact {

    param(
        [string]$Module
    )

    Write-TextFile `
        -Path (Get-ModuleFile $Module "Validation") `
        -Content @(
"import { z } from 'zod';",
"",
"export const ${Module}Schema = z.object({",
"    id: z.string().optional()",
"});",
"",
