function New-CrudArtifacts {

    param(
        [string]$Module
    )

    Write-Section "Generating CRUD Layer"

    New-TypeArtifact $Module

    New-RepositoryArtifact $Module

    New-ServiceArtifact $Module

    New-HookArtifact $Module

    New-ValidationArtifact $Module

